<?php
namespace App\Livewire\Billing\Settings;
use App\Models\PaymentMethod; use Illuminate\Support\Facades\Gate; use Illuminate\Validation\Rule; use Livewire\Component; use Livewire\WithPagination; use Masmerise\Toaster\Toaster as Notifier;
class PaymentMethods extends Component { use WithPagination; public bool $showModal=false; public ?int $editingId=null; public array $form=['name'=>'','code'=>'','type'=>'cash','requires_reference'=>false,'requires_phone'=>false,'requires_bank'=>false,'is_cash'=>false,'is_active'=>true]; public function mount(): void { Gate::authorize('billing.manage-payment-methods'); } public function create(): void {$this->editingId=null;$this->form=['name'=>'','code'=>'','type'=>'cash','requires_reference'=>false,'requires_phone'=>false,'requires_bank'=>false,'is_cash'=>false,'is_active'=>true];$this->showModal=true;} public function edit(int $id): void {$m=PaymentMethod::query()->forCurrentFacility()->findOrFail($id);$this->editingId=$m->id;$this->form=$m->only(array_keys($this->form));$this->showModal=true;} public function save(): void { $data=$this->validate(['form.name'=>['required','max:120'],'form.code'=>['required','max:50',Rule::unique('payment_methods','code')->where('facility_id',currentFacility()?->id)->ignore($this->editingId)],'form.type'=>['required'],'form.requires_reference'=>['boolean'],'form.requires_phone'=>['boolean'],'form.requires_bank'=>['boolean'],'form.is_cash'=>['boolean'],'form.is_active'=>['boolean']])['form']; $data['facility_id']=currentFacility()?->id; $data['code']=str($data['code'])->upper()->replace(' ','_')->toString(); $data['created_by'] ??= auth()->id(); $data['updated_by']=auth()->id(); PaymentMethod::query()->updateOrCreate(['id'=>$this->editingId],$data); $this->showModal=false; Notifier::success('messages.saved'); } public function render(){ return view('livewire.billing.settings.payment-methods',['methods'=>PaymentMethod::query()->forCurrentFacility()->orderBy('sort_order')->paginate(12)])->layout('components.layouts.app',['title'=>'Payment Methods','description'=>'Njia za malipo bila external API integration.']); } }
